import ssl

import certifi


def default_ssl_context() -> ssl.SSLContext:
    """Create and return an SSLContext configured to use certifi's CA bundle.

    This context uses the system defaults and explicitly loads the certificate
    authority bundle provided by the certifi package to ensure up-to-date
    trusted root certificates.
    """
    context = ssl.create_default_context()
    context.load_verify_locations(certifi.where())
    return context